const apiResponse = $('API: Match-Statistics').first().json;
const matchId = $('Webhook Match-Statistics').first().json.body.match_id;
if (!apiResponse.response || apiResponse.response.length === 0) return [];

const mapping = {
  'Shots on Goal': 'goal_on_target_scoring_attempt',
  'Total Shots': 'goal_scoring_attempt',
  'Fouls': 'fouls',
  'Corner Kicks': 'corner_taken',
  'Offsides': 'total_offside',
  'Ball Possession': 'possession_percentage',
  'Yellow Cards': 'yellow_cards',
  'Total passes': 'total_pass',
  'Passes accurate': 'accurate_pass'
};

return apiResponse.response.map(teamData => {
  const stats = {};
  for (const stat of teamData.statistics) {
    const col = mapping[stat.type];
    if (!col) continue;
    let value = stat.value;
    if (value === null || value === undefined) value = 0;
    if (typeof value === 'string') {
      value = parseInt(value.replace('%', '')) || 0;
    }
    stats[col] = value;
  }
  return {
    json: {
      match_id: matchId,
      team_external_id: teamData.team.id,
      goal_on_target_scoring_attempt: stats.goal_on_target_scoring_attempt ?? 0,
      goal_scoring_attempt: stats.goal_scoring_attempt ?? 0,
      fouls: stats.fouls ?? 0,
      corner_taken: stats.corner_taken ?? 0,
      total_offside: stats.total_offside ?? 0,
      possession_percentage: String(stats.possession_percentage ?? 0),
      yellow_cards: stats.yellow_cards ?? 0,
      total_pass: stats.total_pass ?? 0,
      accurate_pass: stats.accurate_pass ?? 0
    }
  };
});
